#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int cmp(const void *a, const void *b) {
    return (*(int*)b - *(int*)a); // descending order
}

void solve() {
    int m, n, k;
    scanf("%d %d %d", &m, &n, &k);

    int *first_array = (int*)malloc(m * sizeof(int));
    int *second_array = (int*)malloc(m * sizeof(int));
    int *vv = (int*)malloc(m * sizeof(int));

    for (int i = 0; i < m; ++i) {
        scanf("%d", &first_array[i]);
    }

    for (int i = 0; i < m; ++i) {
        scanf("%d", &second_array[i]);
    }

    long ans = -1;
    long low = 0, high = 10000000;

    while (low <= high) {
        long mid = low + (high - low) / 2;

        for (int i = 0; i < m; ++i) {
            if (first_array[i] > mid) {
                vv[i] = 0;
                continue;
            }
            long p = mid - first_array[i];
            long q = p / second_array[i];
            vv[i] = q + 1;
        }

        qsort(vv, m, sizeof(int), cmp); // sort in descending order

        long c = 0;
        for (int i = 0; i < (m < n ? m : n); ++i) { // min(m-1, n-1) is essentially min(m,n)
            c += vv[i];
        }

        if (c >= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    printf("%ld\n", ans);

    free(first_array);
    free(second_array);
    free(vv);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        solve();
    }
    return 0;
}

