import java.util.*;
import java.lang.*;
import java.io.*;

class Main {
    public static void main(String[] args) throws Exception {
        // Use BufferedReader for faster input
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        // Read number of test cases
        int t = Integer.parseInt(br.readLine());
        while (t-- > 0) {
            solve(br);
        }
    }

    static void solve(BufferedReader br) throws Exception {
        // Read input values
        String[] inputs = br.readLine().split(" ");
        int m = Integer.parseInt(inputs[0]);
        int n = Integer.parseInt(inputs[1]);
        int k = Integer.parseInt(inputs[2]);

        // Vector to store pairs of integers
        List<Pair> v = new ArrayList<>();

        // Read the first set of integers and populate the vector
        String[] aInputs = br.readLine().split(" ");
        for (int i = 0; i < m; i++) {
            int a = Integer.parseInt(aInputs[i]);
            v.add(new Pair(a, 0));
        }

        // Read the second set of integers and update the vector
        String[] bInputs = br.readLine().split(" ");
        for (int i = 0; i < m; i++) {
            int a = Integer.parseInt(bInputs[i]);
            v.get(i).second = a;
        }

        long ans = -1;
        long low = 0, high = 10000000;

        // Binary search to find the answer
        while (low <= high) {
            long mid = low + (high - low) / 2;
            List<Long> vv = new ArrayList<>();

            for (int i = 0; i < m; i++) {
                if (v.get(i).first > mid) {
                    vv.add(0L);
                    continue;
                }
                long p = mid - v.get(i).first;
                long q = p / v.get(i).second;
                vv.add(q + 1);
            }

            Collections.sort(vv, Collections.reverseOrder());
            long c = 0;
            for (int i = 0; i < (m < n ? m : n); ++i) {
                c += vv.get(i);
            }

            if (c >= k) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        // Output the result
        System.out.println(ans);
    }

    // Pair class to store pairs of integers
    static class Pair {
        int first;
        int second;

        Pair(int first, int second) {
            this.first = first;
            this.second = second;
        }
    }
}

