function solve() {
    const [m, n, k] = readLine().split(' ').map(Number);  // Read m, n, k
    const v_first = readLine().split(' ').map(Number);    // First set of inputs
    const v_second = readLine().split(' ').map(Number);   // Second set of inputs

    const v = [];  // Pair array
    for (let i = 0; i < m; i++) {
        v.push([v_first[i], v_second[i]]);
    }

    let ans = -1;
    let low = 0, high = 10000000;  // Set high to a large value (1e7)

    while (low <= high) {
        const mid = Math.floor(low + (high - low) / 2);
        const vv = [];

        for (let i = 0; i < m; i++) {
            if (v[i][0] > mid) {
                vv.push(0);
                continue;
            }

            const p = mid - v[i][0];
            const q = Math.floor(p / v[i][1]);
            vv.push(q + 1);
        }

        vv.sort((a, b) => b - a);  // Sort vv in descending order

        let c = 0;
        for (let i = 0; i < (m < n ? m : n); i++) {
            c += vv[i];
        }

        if (c >= k) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    console.log(ans);
}

